import { Hono } from 'hono';
import { z } from 'zod';

const app = new Hono();

const NotificationSchema = z.object({
  id: z.string(),
  title: z.string(),
  message: z.string(),
  isRead: z.boolean(),
});

type Notification = z.infer<typeof NotificationSchema>;

app.get('/notifications', async (c) => {
  // Simulate fetching user's notifications from a database
  const notifications: Notification[] = [
    { id: '1', title: 'New Order', message: 'Your order has been shipped.', isRead: false },
    { id: '2', title: 'Product Update', message: 'Check out our new product!', isRead: true },
    { id: '3', title: 'Order Confirmation', message: 'Thank you for your purchase.', isRead: true },
  ];

  // Pagination parameters
  const page = c.req.query('page') || '1';
  const limit = c.req.query('limit') || '10';

  // Parse pagination parameters as integers
  const parsedPage = parseInt(page, 10);
  const parsedLimit = parseInt(limit, 10);

  if (isNaN(parsedPage) || isNaN(parsedLimit)) {
    return c.json({ error: 'Invalid page or limit' }, 400);
  }

  // Calculate pagination offsets
  const offset = (parsedPage - 1) * parsedLimit;

  // Sort notifications by isRead, unread first
  const sortedNotifications = notifications.sort((a, b) => a.isRead === b.isRead ? 0 : a.isRead ? 1 : -1);

  // Slice the array based on pagination parameters
  const paginatedNotifications = sortedNotifications.slice(offset, offset + parsedLimit);

  return c.json(paginatedNotifications);
});

export default app;

